from __future__ import annotations
from dataclasses import dataclass, field
from typing import Dict, List, Optional
import torch

@dataclass
class PhysicalBlock:
    block_id: int
    ref_count: int = 0   # >1 means shared (copy-on-write)

class BlockAllocator:
    def __init__(self, num_blocks: int, block_size: int):
        self.block_size = block_size
        self.blocks: List[PhysicalBlock] = [PhysicalBlock(i) for i in range(num_blocks)]
        self.free_list: List[int] = list(range(num_blocks))

    def allocate(self) -> PhysicalBlock:
        if not self.free_list:
            raise MemoryError("No free KV cache blocks — need to preempt a request")
        block_id = self.free_list.pop()
        blk = self.blocks[block_id]
        blk.ref_count = 1
        return blk

    def free(self, blk: PhysicalBlock) -> None:
        blk.ref_count -= 1
        if blk.ref_count == 0:
            self.free_list.append(blk.block_id)

    def fork(self, blk: PhysicalBlock) -> None:
        """Increment ref_count for copy-on-write sharing (beam search)."""
        blk.ref_count += 1

    @property
    def num_free_blocks(self) -> int:
        return len(self.free_list)


class BlockTable:
    """Maps logical block index -> physical block for one sequence."""
    def __init__(self, allocator: BlockAllocator):
        self.allocator = allocator
        self.logical_to_physical: List[PhysicalBlock] = []

    def append_token(self, pos: int) -> None:
        """Ensure a physical block exists for the token at position `pos`."""
        block_idx = pos // self.allocator.block_size
        if block_idx >= len(self.logical_to_physical):
            blk = self.allocator.allocate()
            self.logical_to_physical.append(blk)

    def get_physical_ids(self) -> List[int]:
        return [b.block_id for b in self.logical_to_physical]

    def free_all(self) -> None:
        for blk in self.logical_to_physical:
            self.allocator.free(blk)
        self.logical_to_physical.clear()


# Example: two concurrent sequences
allocator = BlockAllocator(num_blocks=64, block_size=16)
seq_a = BlockTable(allocator)
seq_b = BlockTable(allocator)

# Seq A generates 48 tokens (needs 3 blocks), Seq B generates 20 (needs 2 blocks)
for i in range(48):
    seq_a.append_token(i)
for i in range(20):
    seq_b.append_token(i)

print(f"Seq A physical blocks: {seq_a.get_physical_ids()}")  # 3 blocks
print(f"Seq B physical blocks: {seq_b.get_physical_ids()}")  # 2 blocks
print(f"Free blocks remaining: {allocator.num_free_blocks}")  # 64-5 = 59
